THE CLAIM:
{
 "title": "Large-operator sales are locked up by long-term framework deals",
 "narrative": "The model names large operators as the first buyer and prices that cell at 40% of spend. But those operators buy rack power through multi-year framework contracts, like the Digital Realty–Schneider $373M deal, that remove the tender from the market for the whole term. If most of that 40% is already under contract, the Year-1 beachhead is closed and the number shifts onto slower cells.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Large operators extend multi-year framework deals with incumbent vendors",
   "refs": [
    "digest:cust-mix#c12",
    "digest:cr3-vendors#c1",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "propagation",
   "text": "No open bid reaches the market during the contract term",
   "refs": [
    "profile:Stage",
    "ledger:cust.operator-large",
    "digest:cust-mix#c0"
   ]
  },
  {
   "step": "model-impact",
   "text": "The reachable large-operator share falls from 40% to about 20%",
   "refs": [
    "ledger:cust.operator-large",
    "ledger:obtainableFactor",
    "digest:cust-mix#c0"
   ]
  }
 ],
 "falsifier": "Two or more large operators issuing open, multi-vendor rack-PDU bids within the next 12 months.",
 "category": "competitive",
 "evidence": [
  {
   "title": "Schneider Electric and Digital Realty Announce $373M Supply Capacity Agreement",
   "sourceType": "industry-report",
   "publisher": "PR Newswire / Schneider Electric",
   "date": "2025-11-19",
   "excerpt": "has signed a $373 million Supply Capacity Agreement (SCA) for UPS, Low Voltage Switchgear, and Pre-Fabricated Skids... The strategic shift to an SCA model provides guaranteed capacity... while preserving the flexibility needed for a dynamic, multi-vendor environment to mitigate risk.",
   "url": "https://www.prnewswire.com/news-releases/schneider-electric-and-digital-realty-announce-373m-supply-capacity-agreement-to-meet-rising-data-center-demand-302620427.html",
   "attached": true
  },
  {
   "title": "HD Hyundai Electric Signs $1.1 Billion Supply Deal with Big Tech for North American Data Centers",
   "sourceType": "industry-report",
   "publisher": "AJU Press",
   "date": "2026-07-02",
   "excerpt": "entered into a basic contract for a long-term supply of distribution and power equipment worth up to $1.1 billion... Supplying both types of equipment together enhances the design consistency... and reduces risks in delivery, quality, and after-sales service.",
   "url": "https://m.ajupress.com/view/20260702112470315",
   "attached": true
  },
  {
   "title": "Supply Chain and Technology Agreements in Data Center Construction",
   "sourceType": "industry-report",
   "publisher": "Bracewell LLP / JD Supra",
   "date": "2026-01-27",
   "excerpt": "data center operators are increasingly relying on robust supply chain and technology agreements that include component shortage remedies, price adjustment clauses, alternative sourcing clauses as well as revamped force majeure.",
   "url": "https://www.jdsupra.com/legalnews/supply-chain-and-technology-agreements-1931379/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "cust.operator-large",
  "label": "Large operators",
  "kind": "estimated",
  "value": 0.4,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": "customerType",
  "dimensionValue": "operator-large",
  "sensitivityRange": {
   "low": 0.33,
   "high": 0.47
  },
  "funnelActive": true,
  "derivation": {
   "method": "Qualitative channel triangulation",
   "expression": "Hyperscale+colo ≈ 62% of capacity (Synergy) and large operators buy direct → dominant buyer ≈ 0.40 of PDU spend"
  },
  "provenance": {
   "rationale": "Report segmentations name the channels (direct/OEM/distributor) but publish no percentages → internal estimate.",
   "promotionPath": "Validate buyer mix with 3 CE operator/distributor interviews."
  },
  "evidence": [
   {
    "title": "Data center growth driving power equipment sales",
    "sourceType": "analyst-estimate",
    "publisher": "Alexander Group",
    "date": "2026-06-19",
    "excerpt": "One leading supplier reported data centers as its biggest growth driver, accounting for 30% of orders in 2025 — qualitative channel context only.",
    "attached": true
   },
   {
    "title": "CE operator & distributor interviews",
    "sourceType": "pending",
    "publisher": null,
    "date": null,
    "excerpt": "Three structured interviews would replace this qualitative split with a sourced one.",
    "attached": false
   }
  ]
 },
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
